import graphene
import psycopg2
from psycopg2.extras import RealDictCursor
from typing import List, Optional
import re

class SearchInput(graphene.InputObjectType):
    query = graphene.String(required=True)
    fields = graphene.List(graphene.String)
    limit = graphene.Int(default_value=100)
    offset = graphene.Int(default_value=0)

class SearchResult(graphene.ObjectType):
    id = graphene.Int()
    name = graphene.String()
    description = graphene.String()
    created_at = graphene.DateTime()

class SearchQuery(graphene.ObjectType):
    search = graphene.List(
        SearchResult,
        search_input=graphene.Argument(SearchInput, required=True)
    )

    def resolve_search(self, info, search_input):
        conn = None
        try:
            conn = psycopg2.connect(
                host="localhost",
                database="your_db",
                user="your_user",
                password="your_password"
            )
            cursor = conn.cursor(cursor_factory=RealDictCursor)
            
            query = search_input.query
            fields = search_input.fields or ['name', 'description']
            limit = search_input.limit
            offset = search_input.offset
            
            # Sanitize input to prevent SQL injection
            if not re.match(r'^[a-zA-Z0-9\s\-\_\.]+$', query):
                raise ValueError("Invalid search query")
            
            # Build dynamic WHERE clause
            where_conditions = []
            params = []
            
            for i, field in enumerate(fields):
                if field not in ['id', 'name', 'description', 'created_at']:
                    continue
                where_conditions.append(f"{field} ILIKE %s")
                params.append(f"%{query}%")
            
            if not where_conditions:
                raise ValueError("No valid fields for search")
            
            where_clause = " OR ".join(where_conditions)
            
            # Build final query
            sql = f"""
                SELECT id, name, description, created_at
                FROM your_table
                WHERE {where_clause}
                ORDER BY created_at DESC
                LIMIT %s OFFSET %s
            """
            
            params.extend([limit, offset])
            
            cursor.execute(sql, params)
            results = cursor.fetchall()
            
            return [
                SearchResult(
                    id=row['id'],
                    name=row['name'],
                    description=row['description'],
                    created_at=row['created_at']
                ) for row in results
            ]
            
        except Exception as e:
            raise Exception(f"Search failed: {str(e)}")
        finally:
            if conn:
                conn.close()

schema = graphene.Schema(query=SearchQuery)